import "@radix-ui/themes/styles.css";
import { Box, ThemePanel, Container, Flex, Section, Heading, Text} from "@radix-ui/themes";
import './App.css';
import { useState } from "react";

const About = () => {
    return (
        <Box id = "about">
        <Box mt="7">
            <Text size="4" style={{color: "rgba(255, 255, 255, 0.73)"}}>
                Hey, I'm Ted Fawke, a full stack web developer with a business oriented mindset. I love everything about the internet and I'm always interested in learning new technologies. My approach to software development is always to keep the user as my guiding light, and to create as good an experience as possible.
            </Text>
            <Box>
            <Text mt="4" size="4" style={{color: "rgba(255, 255, 255, 0.73)"}}>
                I'm currently working at Paramount Web Technology, where we create custom e-commerce solutions for businesses all around the world. Woocommerce and Wordpress are our bread and butter, but we also branch out into other technologies, such as React and Node.js.
            </Text>
            </Box>
        </Box>
        </Box>
    )
}

export default About;
